import "./styles/app.css"
import { HtmlHTMLAttributes, useRef } from "react";
function App() {
  const ref=useRef<HTMLDivElementAttributes>("");

  return (

    <div ref={ref} className="page guide-page">
       <img alt="" className="main-pic" src ={require('./img/logo_@2x.png')} />
       <p className="title">欢乐购</p>
       <img alt="" className="sub-pic" src ={require('./img/slogn_word_icon_@2x.png')} />
       <div className="iconfont arrow-icon">&#xe60c;</div>
    </div>
  );
}

export default App;
